const raw = $input.item.json.output || "";

// Очищаем markdown-обёртку если агент добавил ```json ... ```
let cleaned = raw.trim();
if (cleaned.startsWith("```")) {
  cleaned = cleaned.replace(/^```[a-z]*\n?/, "").replace(/\n?```$/, "").trim();
}

// Пробуем найти JSON-объект внутри текста (на случай если агент добавил текст до/после)
const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
if (jsonMatch) {
  cleaned = jsonMatch[0];
}

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  // Если всё равно не парсится — возвращаем текст как answer, этап не меняем
  return [{
    json: {
      answer: raw.trim(),
      current_stage: "FORMAT",
      task_bank: ""
    }
  }];
}

return [{
  json: {
    answer: parsed.answer ?? "",
    current_stage: parsed.current_stage ?? "FORMAT",
    task_bank: parsed.task_bank ?? ""
  }
}];

