// Текущая дата по МСК (UTC+3)
const nowMsk = new Date(Date.now() + 3 * 60 * 60 * 1000);
const todayY = nowMsk.getUTCFullYear();
const todayM = nowMsk.getUTCMonth(); // 0-based
const todayD = nowMsk.getUTCDate();

const ruMonths = {
  'января':0,'февраля':1,'марта':2,'апреля':3,'мая':4,'июня':5,
  'июля':6,'августа':7,'сентября':8,'октября':9,'ноября':10,'декабря':11,
  'январь':0,'февраль':1,'март':2,'апрель':3,'май':4,'июнь':5,
  'июль':6,'август':7,'сентябрь':8,'октябрь':9,'ноябрь':10,'декабрь':11
};

function isToday(raw) {
  if (!raw) return false;
  const s = String(raw).toLowerCase().trim();

  if (s.includes('сегодня')) return true;
  if (s.includes('завтра') || s.includes('послезавтра')) return false;

  // ISO: 2026-03-01 или 2026/03/01
  const iso = s.match(/(\d{4})[-/](\d{1,2})[-/](\d{1,2})/);
  if (iso) {
    const [,y,m,d] = iso.map(Number);
    return y===todayY && (m-1)===todayM && d===todayD;
  }

  // DD.MM.YYYY или DD/MM/YYYY
  const dmy = s.match(/(\d{1,2})[./](\d{1,2})[./](\d{4})/);
  if (dmy) {
    const [,d,m,y] = dmy.map(Number);
    return y===todayY && (m-1)===todayM && d===todayD;
  }

  // «3 марта» или «3 марта 2026»
  const ru = s.match(/(\d{1,2})\s+([а-яё]+)(\s+\d{4})?/);
  if (ru) {
    const d = parseInt(ru[1]);
    const month = ruMonths[ru[2]];
    const y = ru[3] ? parseInt(ru[3].trim()) : todayY;
    if (month !== undefined) return y===todayY && month===todayM && d===todayD;
  }

  return false;
}

const results = [];
for (const item of $input.all()) {
  const row = item.json;
  if (row.current_stage === 'WAIT_CARD' && row.cuid && isToday(row.delivery_datetime)) {
    results.push({ json: row });
  }
}

return results.length > 0 ? results : [{ json: { _skip: true } }];

