const raw = $input.item.json.output;
const parsed = JSON.parse(raw);
return [{
  json: {
    answer: parsed.answer ?? "",
    current_stage: parsed.current_stage,
    card_received: parsed.card_received === true
  }
}];

// Convert binary file to base64 for OpenAI Vision API
const items = $input.all();
const item = items[0];
const binaryData = item.binary?.data;

if (!binaryData) {
  return [{json: {error: "no_binary_data"}}];
}

const buffer = await this.helpers.getBinaryDataBuffer(0, "data");
const base64 = buffer.toString("base64");

let mimeType = binaryData.mimeType || "image/jpeg";
const fileName = (binaryData.fileName || "").toLowerCase();

if (mimeType === "application/octet-stream" || !mimeType.startsWith("image/")) {
  if (fileName.endsWith(".jpg") || fileName.endsWith(".jpeg")) {
    mimeType = "image/jpeg";
  } else if (fileName.endsWith(".png")) {
    mimeType = "image/png";
  } else if (fileName.endsWith(".webp")) {
    mimeType = "image/webp";
  } else {
    mimeType = "image/jpeg";
  }
}

const userData = $("Читаем данные пользователя").first().json;
const taskBank = userData.task_bank || "";

// Минимальная сумма по банку
const minPurchaseMap = {
  "vtb_bank": 500,
  "tbank_bank": 100,
  "alfa_bank": 100,
  "otp_bank": 100,
  "gpb_bank": 100
};
const minPurchase = minPurchaseMap[taskBank] || 100;

return [{json: {
  base64,
  mimeType,
  chatId: $("Telegram Trigger").first().json.message.chat.id,
  cuid: userData.cuid,
  task_bank: taskBank,
  min_purchase: minPurchase,
  name: userData.name
}}];

